function extractGeminiText(resp) {
  if (!resp) return '';
  if (resp.candidates && resp.candidates[0] && resp.candidates[0].content && resp.candidates[0].content.parts) {
    return resp.candidates[0].content.parts[0].text || '';
  }
  return resp.text || '';
}

const leadResp = $('リード＋総括 LLM Chain').first().json;
const titleResp = $('タイトル生成 LLM Chain').first().json;

const leadRawStr = extractGeminiText(leadResp);
const titleText = extractGeminiText(titleResp).trim().replace(/^["「]|["」]$/g, '').split('\n')[0].trim();

let leadJson;
try {
  const cleaned = leadRawStr.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
  leadJson = JSON.parse(cleaned);
} catch(e) { leadJson = {lead:'', closing:''}; }


// closingを1400字以内に収める（文章境界で切る）
function truncateAtSentence(text, maxLen) {
  if (!text || text.length <= maxLen) return text;
  const cut = text.substring(0, maxLen);
  const lastPeriod = Math.max(cut.lastIndexOf('。'), cut.lastIndexOf('．'), cut.lastIndexOf('\n\n'));
  return lastPeriod > maxLen * 0.5 ? cut.substring(0, lastPeriod + 1) : cut;
}
const lead = leadJson.lead || '';
const closing = truncateAtSentence(leadJson.closing || '', 1400);
const newsBody = $('記事本文組立Code').first().json.news_body || '';
const newsData = $('記事本文組立Code').first().json.news_data || [];

const nl = '\n';
const finalArticle = [
  '# ' + titleText,
  '',
  lead,
  '',
  newsBody,
  '## ◆ 総括：時代の濁流を読み解く',
  '',
  closing,
  ''
].join(nl);

const now = new Date();
// JST = UTC + 9h
const jstNow = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const dateStr = String(jstNow.getUTCFullYear())
  + String(jstNow.getUTCMonth()+1).padStart(2,'0')
  + String(jstNow.getUTCDate()).padStart(2,'0')
  + '-'
  + String(jstNow.getUTCHours()).padStart(2,'0')
  + String(jstNow.getUTCMinutes()).padStart(2,'0')
  + String(jstNow.getUTCSeconds()).padStart(2,'0');

return [{
  json: {
    final_article: finalArticle,
    final_title: titleText,
    lead_text: lead,
    closing_text: closing,
    news_data: newsData,
    slug: dateStr,
    publishDate: jstNow.toISOString()
  }
}];

const data = $input.first().json;
const title = data.final_title || '';
const closingText = data.closing_text || '';
const newsData = data.news_data || [];

const GEMINI_KEY = '***GEMINI_KEY***';
const GEMINI_URL = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${GEMINI_KEY}`;

const jstNow = new Date(new Date().getTime() + 9 * 60 * 60 * 1000);
const dayOfWeek = jstNow.getUTCDay();

// ========================================
// カバー画像: MOEBIUS_BASE + 曜日カラー + トーン別シーン
// ========================================
const COVER_PALETTES = [
  { sky: 'near-black midnight navy sky with pale crescent moon', sea: 'deep blue-black sea with luminous white wave crests', earth: 'cool ash-white shore' },
  { sky: 'deep saturated cobalt turquoise sky with wispy clouds', sea: 'teal green sea with hatched waves', earth: 'warm amber sandy beach' },
  { sky: 'deep crimson and burnt sienna sky with dramatic clouds', sea: 'dark rust-orange sea with heavy crosshatch waves', earth: 'pale ash-white shore' },
  { sky: 'deep forest green and jade sky with rising mist', sea: 'dark moss-green sea with fine hatched waves', earth: 'warm ochre earth' },
  { sky: 'deep golden amber sky with radiant light beams', sea: 'warm copper-gold sea', earth: 'rich caramel shore' },
  { sky: 'deep violet and indigo sky with ink star clusters', sea: 'dark plum and midnight-blue sea', earth: 'lavender-grey shore' },
  { sky: 'ash grey and charcoal sky with stark cloud formations', sea: 'dark pewter-silver sea with geometric crosshatching', earth: 'white chalk shore' }
];
const pal = COVER_PALETTES[dayOfWeek];
const MOEBIUS_COVER = 'no signature no text no numbers, Moebius bande dessinee panel, strong black ink outlines ligne claire, rich crosshatching, transparent watercolor washes, ' + pal.sky + ', ' + pal.sea + ', ' + pal.earth + ', {SCENE}, extremely tiny human silhouette at water edge, tiny bird in sky, wide panoramic composition, overwhelming scale of nature, analog warmth';

function detectTone(t, c) {
  const txt = t + c;
  const a = ['崩壊','危機','警告','失う','終焉','脅威','拒否','閉鎖','制裁'].filter(w => txt.includes(w)).length;
  const c2 = ['希望','未来','解決','創造','革新','拓く','投資','成長'].filter(w => txt.includes(w)).length;
  return a >= c2 ? 'A' : c2 > 0 ? 'C' : 'B';
}
const coverScenes = {
  A: ['enormous ruined towers looming over flooded plain, dark storm clouds, lone silhouette on collapsed bridge', 'fractured architecture collapsing into dark abyss, storm light breaking through cracks', 'vast mechanical structures rising from crumbling city, jagged metal spires piercing low clouds'],
  B: ['hidden geometric light patterns emerging beneath ocean surface, observer tracing revelations at cliff edge', 'ancient ruins revealing glowing circuit engravings at dawn, mist lifting from valley', 'giant luminous map of interconnected nodes floating above dark terrain'],
  C: ['new city under construction at golden dawn, cranes silhouetted against warm amber sky', 'seeds of light rising from cupped hands into vast night sky each becoming a star', 'bridge spanning vast canyon at sunrise, two groups building toward each other in morning mist']
};
const tone = detectTone(title, closingText);
const sceneIdx = jstNow.getUTCSeconds() % 3;
const coverPrompt = MOEBIUS_COVER.replace('{SCENE}', coverScenes[tone][sceneIdx]);

// ========================================
// ニュース画像: Gemini APIで記事内容から視覚描写を生成（順次処理）
// ========================================
const NEWS_COLORS = [
  'cobalt blue and silver palette',
  'crimson red and warm ivory palette',
  'forest green and golden ochre palette',
  'deep violet and lavender palette'
];
const MOEBIUS_NEWS_BASE = 'Moebius bande dessinee panel, ligne claire black ink outlines, detailed crosshatching and stippling, transparent watercolor wash, editorial illustration, no text no numbers, {COLOR}, {SCENE}';
const FALLBACK_SCENES = [
  'vast server farm with towering glowing racks extending to horizon, cool blue mechanical light',
  'semiconductor fabrication room with robotic arms positioned over silicon wafer, microscopic circuit details',
  'financial district aerial view with skyscrapers forming bar chart silhouette, economic architecture',
  'satellite network diagram with orbital paths around earth, geometric trajectory lines, cosmic scale'
];

async function getGeminiScene(headline, summary, fallback) {
  const userPrompt = 'You are writing image prompts for editorial illustrations about tech news.\n\nBased on the article below, describe a specific visual scene in English (40-60 words).\nRules:\n- Describe real-world OBJECTS and SETTINGS matching the news topic: drones, microchips, robots, buildings, financial charts, satellites, etc.\n- Be specific to THIS article, not generic\n- NO people\'s faces, NO two figures facing each other\n- Output ONLY the scene description, no intro, no explanation\n\nHeadline: ' + headline + '\nSummary: ' + summary.substring(0, 600);

  try {
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: GEMINI_URL,
      headers: { 'Content-Type': 'application/json' },
      body: {
        contents: [{ parts: [{ text: userPrompt }] }],
        generationConfig: { maxOutputTokens: 300, temperature: 0.7 }
      },
      json: true
    });
    const text = ((resp && resp.candidates && resp.candidates[0] && resp.candidates[0].content && resp.candidates[0].content.parts && resp.candidates[0].content.parts[0] && resp.candidates[0].content.parts[0].text) || '').trim();
    if (text && text.length > 20) return text;
    return fallback;
  } catch (e) {
    return fallback;
  }
}

// 順次処理（Promise.allではなくfor loopで安定実行）
const newsItems = newsData.slice(0, 4);
const scenes = [];
for (let i = 0; i < newsItems.length; i++) {
  const item = newsItems[i];
  const headline = item.japanese_headline || item.original_title || '';
  const summary = item.fact_summary || item.summary || item.body || '';
  const scene = await getGeminiScene(headline, summary, FALLBACK_SCENES[i]);
  scenes.push(scene);
}

const prompts = [{ type: 'cover', prompt: coverPrompt }];
for (let i = 0; i < newsItems.length; i++) {
  const prompt = MOEBIUS_NEWS_BASE
    .replace('{COLOR}', NEWS_COLORS[i])
    .replace('{SCENE}', scenes[i]);
  prompts.push({ type: 'news_' + i, prompt });
}

return prompts.map(p => ({ json: p }));

const items = $input.all();
// 生成順序: cover → news_0 → news_1 → news_2 → news_3
const typeOrder = ["cover", "news_0", "news_1", "news_2", "news_3"];
const urls = {};
items.forEach((item, i) => {
  // Cloudinaryのレスポンスにはtype:"upload"が含まれ上書きされるため
  // インデックスで強制的にtype割り当て
  const type = typeOrder[i] || ("item_" + i);
  const url = item.json.secure_url || item.json.url || "";
  if (url) urls[type] = url;
});
return [{ json: { image_urls: urls } }];

const imageData = $input.first().json;
const articleData = $("最終組立Code").first().json;
let article = articleData.final_article || '';
const urls = imageData.image_urls || {};

// カバー画像：タイトル行直後に挿入
if (urls.cover) {
  article = article.replace(/^(# [^\n]+\n\n)/, '$1![カバー画像](' + urls.cover + ')\n\n');
}

// ニュース画像：「### ◆ タイトル\n\n**配信日」の直前に挿入
// replace()はgフラグなし → 毎回最初のマッチだけ置換 → ループで順番に差し込まれる
for (let i = 0; i < 4; i++) {
  const newsUrl = urls['news_' + i];
  if (newsUrl) {
    article = article.replace(
      /(### ◆ [^\n]+\n\n)(\*\*配信日)/,
      '$1![ニュース画像](' + newsUrl + ')\n\n$2'
    );
  }
}

return [{ json: { ...articleData, final_article: article, image_urls: urls } }];

const data = $input.first().json;
const article = data.final_article || '';
const title = data.final_title || '';
const lead = data.lead_text || '';
const slug = data.slug || '';
const coverUrl = (data.image_urls || {}).cover || (data.image_urls || {}).upload || '';
const publishDate = data.publishDate || new Date().toISOString();
const dateFormatted = publishDate.substring(0, 10) + ' ' + publishDate.substring(11, 16);

const mdx = `---
title: "${title.replace(/"/g, '\\"')}"
lead: "${lead.replace(/"/g, '\\"')}"
date: "${dateFormatted}"
category: "AI"
