// Perplexityの4件レスポンスを全て処理して4件返す
const perplexityItems = $input.all();
const originalItems = $('件数チェックCode').all();
const results = [];

for (let i = 0; i < perplexityItems.length; i++) {
  const resp = perplexityItems[i].json;
  const original = originalItems[i] ? originalItems[i].json : {};

  // Perplexityレスポンスからテキスト取得
  const text = resp.choices && resp.choices[0] ? resp.choices[0].message.content : '';
  let enriched = {};
  try {
    const cleaned = text.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
    enriched = JSON.parse(cleaned);
  } catch(e) {
    enriched = {};
  }

  results.push({ json: {
    title: enriched.title || original.title || '',
    url: enriched.url || original.url || '',
    source_media: original.source_media || enriched.source_media || '',
    pubDate: enriched.pubDate || original.pubDate || '',
    summary: (enriched.content || enriched.summary || original.summary || '').substring(0, 600)
  }});
}

return results;
